// Path 1 (sense-safe): greedy compute-preconditioning on 1.7b with THREE gates on every swap:
//   1. fluency  — POS-preserving + correctly re-inflected (fluency-gate)
//   2. SENSE    — contextual-embedding cosine(slot-lemma, synonym-lemma) ≥ 0.40, mean-centered
//                 (the now-FULL contextual dictionary; no vector ⇒ can't verify sense ⇒ reject)
//   3. compute  — measured FFN active_blocks drops AND the generated tokens are IDENTICAL
import fs from 'fs';
import { analyzeSurface, inflectTo } from './fluency-gate.mjs';
const HOME = process.env.HOME;
const SYN = JSON.parse(fs.readFileSync(`${HOME}/.flux-embed/synonyms.json`,'utf8'));
const DB = JSON.parse(fs.readFileSync(`${HOME}/.flux-embed/ctxemb.json`,'utf8'));
const DIM = 896, keys = Object.keys(DB), mean = new Float64Array(DIM);
for (const k of keys) { const v = DB[k]; for (let i=0;i<DIM;i++) mean[i]+=v[i]; }
for (let i=0;i<DIM;i++) mean[i]/=keys.length;
const cen = (w) => { const v=DB[w]; if(!v) return null; const o=new Float64Array(DIM); for(let i=0;i<DIM;i++)o[i]=v[i]-mean[i]; return o; };
const cos = (a,b) => { let d=0,na=0,nb=0; for(let i=0;i<DIM;i++){d+=a[i]*b[i];na+=a[i]*a[i];nb+=b[i]*b[i];} return d/((Math.sqrt(na)*Math.sqrt(nb))||1); };
const SENSE = 0.40;

const vocab = JSON.parse(fs.readFileSync('./apps/edge-workers/vocab-cache/qwen3-8b-temp-vocab.json')).vocab;
const vset = new Set(Object.keys(vocab));
const tok = (t) => { const ids=[]; for (const w of t.toLowerCase().split(/\s+/)) { let s='Ġ'+w; while (s.length){let took='';for(let l=Math.min(s.length,24);l>=1;l--){const c=s.slice(0,l);if(vset.has(c)){took=c;break;}}if(!took){s=s.slice(1);continue;}ids.push(vocab[took]);s=s.slice(took.length);} } return ids; };
const probe = async (t) => { const ids=tok(t); const body=new Uint8Array(ids.length*4); const dv=new DataView(body.buffer); ids.forEach((id,i)=>dv.setUint32(i*4,id>>>0,true)); const j=await(await fetch('http://127.0.0.1:8100/precond-probe',{method:'POST',headers:{'X-Max-New':'4','X-FFN-Leakage-Mode':'mask-input-low-70'},body})).json(); return {perf:(j.active_input+j.active_hidden)/j.forwards,gen:JSON.stringify(j.gen_tokens)}; };
const STOP = new Set('the of a an and or but to in on at for with from his her their its is are was were be been this that as by it he she they we you not no do does did have has had will would can could may very every'.split(' '));

function senseCands(surface) {
  const { ending, lemmas } = analyzeSurface(surface);
  let lemma=null, entry=null;
  for (const l of lemmas) { if (SYN[l]) { lemma=l; entry=SYN[l]; break; } }
  if (!lemma) return [];
  const lc = cen(lemma); if (!lc) return [];
  const out = new Set();
  for (const bucket of Object.keys(entry)) {
    for (const candBase of entry[bucket]) {
      if (candBase === lemma) continue;
      const cc = cen(candBase); if (!cc) continue;            // no vector → reject (can't verify sense)
      if (cos(lc, cc) < SENSE) continue;                       // SENSE GATE
      const surf = inflectTo(candBase, ending, bucket); if (!surf) continue;
      if (vset.has('Ġ'+surf.toLowerCase()) && surf.toLowerCase()!==surface.toLowerCase()) out.add(surf);
    }
  }
  return [...out];
}

const tests = [
  'the man felt very happy today',
  'the task was extremely difficult to complete',
  'an enormous wave struck the small boat',
  'the soldier returned home after the long battle',
  'she discovered a beautiful garden behind the old house',
  'the child laughed loudly at the funny clown',
  'the doctor examined the patient with great care',
  'the river flowed quickly through the narrow valley',
  'the angry crowd gathered outside the courthouse',
  'the scientist measured the temperature carefully',
];
let sum=0,n=0,swaps=0;
for (const orig of tests) {
  const base = await probe(orig); const words = orig.split(/\s+/);
  let cur=[...words], curPerf=base.perf;
  for (let i=0;i<words.length;i++) {
    const surface = words[i].replace(/[^a-z]/gi,'');
    if (STOP.has(surface.toLowerCase()) || surface.length<4) continue;
    for (const s of senseCands(surface)) {
      const trial=[...cur]; trial[i]=words[i].replace(surface, s);
      const r = await probe(trial.join(' '));
      if (r.perf < curPerf-0.5 && r.gen===base.gen) { cur=trial; curPerf=r.perf; swaps++; }
    }
  }
  const pre=cur.join(' '); const fin=await probe(pre);
  const gain=100*(base.perf-fin.perf)/base.perf; sum+=gain; n++;
  console.log(`orig: "${orig}"`);
  console.log(`pre:  "${pre}"  → ${gain>=0?'+':''}${gain.toFixed(1)}% compute  identical:${fin.gen===base.gen}${pre===orig?'  (no swap)':''}\n`);
}
console.log(`MEAN: +${(sum/n).toFixed(2)}% compute · ${swaps} swaps accepted · sense≥${SENSE}, fluency+answer gated`);
